<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_login(); use app\Services\BorrowService; use app\Services\ReturnService; $svc=new ReturnService(); $borrowSvc=new BorrowService(); $borrowId=(int)($_GET['borrow_id']??$_POST['borrow_id']??0); $borrow=$borrowId?$borrowSvc->find($borrowId):null; if($_SERVER['REQUEST_METHOD']==='POST'){ $_POST['created_by']=current_user()['id']; $r=$svc->create($_POST); if($r['ok']){ flash('success','Đã trả tài liệu, phiếu đã tự ẩn khỏi mục mượn'); redirect_to('returns/index.php'); } flash('error',$r['message']??'Dữ liệu không hợp lệ'); } $borrows=$borrowSvc->all('', 'borrowing'); $fine=($borrow&&!empty($_POST['return_date']))?$svc->calculateFine($borrow['due_date'],$_POST['return_date']):0; $title='Tạo phiếu trả'; include ROOT_PATH.'/includes/header.php'; ?><h1 class="h3 mb-3">Tạo phiếu trả</h1><div class="card"><div class="card-body"><form method="post" class="row g-3"><div class="col-md-12"><label class="form-label required">Phiếu mượn đang mượn</label><select name="borrow_id" class="form-select" onchange="location.href='?borrow_id='+this.value"><option value="">-- Chọn phiếu mượn --</option><?php foreach($borrows as $b): ?><option value="<?= $b['id'] ?>" <?= selected($borrowId,$b['id']) ?>><?= e($b['member_name'].' mượn ['.item_type_vi($b['item_type']).'] '.$b['item_title'].' - hạn '.date_vi($b['due_date'])) ?></option><?php endforeach; ?></select></div><?php if($borrow): ?><div class="col-12"><div class="alert alert-info">Tài liệu: <b><?= e('['.item_type_vi($borrow['item_type']).'] '.$borrow['item_title']) ?></b><br>Thành viên: <b><?= e($borrow['member_name']) ?></b><br>Ngày mượn: <?= date_vi($borrow['borrow_date']) ?> - Hạn trả: <?= date_vi($borrow['due_date']) ?></div></div><?php endif; ?><div class="col-md-6"><label class="form-label required">Ngày trả</label><input type="date" name="return_date" class="form-control" value="<?= e($_POST['return_date']??date('Y-m-d')) ?>"></div><div class="col-md-6"><label class="form-label">Tiền phạt dự kiến</label><input class="form-control" value="<?= money_vnd($fine) ?>" disabled></div><div class="col-12"><label class="form-label">Ghi chú</label><textarea name="note" class="form-control"><?= e($_POST['note']??'') ?></textarea></div><div class="col-12"><button class="btn btn-primary">Tạo phiếu trả</button> <a class="btn btn-secondary" href="index.php">Quay lại</a></div></form></div></div><?php include ROOT_PATH.'/includes/footer.php'; ?>
